#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_DEVICES 4

// Bus Request and Grant signals
typedef struct {
 int device_id;
 char name[20];
 int priority; // Higher = more important
 bool breq; // Bus Request signal
 bool bgnt; // Bus Grant signal
 bool using_bus; // Currently owns bus
} BusMaster;

// Central Arbiter structure
typedef struct {
 BusMaster masters[MAX_DEVICES];
 int num_masters;
 int rr_pointer; // Round-robin pointer
 bool arbitration_mode; // false = priority, true = round-robin
} CentralArbiter;

// Initialize the arbiter with devices
void init_arbiter(CentralArbiter *arbiter, bool mode) {
 arbiter->num_masters = MAX_DEVICES;
 arbiter->rr_pointer = 0;
 arbiter->arbitration_mode = mode;

 // Configure devices with different priorities
 strcpy(arbiter->masters[0].name, "CPU");
 arbiter->masters[0].priority = 3;

 strcpy(arbiter->masters[1].name, "DMA");
 arbiter->masters[1].priority = 2;

 strcpy(arbiter->masters[2].name, "Network");
 arbiter->masters[2].priority = 1;

 strcpy(arbiter->masters[3].name, "Sound");
 arbiter->masters[3].priority = 0;

 for (int i = 0; i < MAX_DEVICES; i++) {
 arbiter->masters[i].device_id = i;
 arbiter->masters[i].breq = false;
 arbiter->masters[i].bgnt = false;
 arbiter->masters[i].using_bus = false;
 }
}

// Priority-based arbitration
int priority_arbration(CentralArbiter *arbiter) {
 int highest_priority = -1;
 int winner = -1;

 for (int i = 0; i < arbiter->num_masters; i++) {
 if (arbiter->masters[i].breq) {
 if (arbiter->masters[i].priority > highest_priority) {
 highest_priority = arbiter->masters[i].priority;
 winner = i;
 }
 }
 }
 return winner;
}

// Round-robin arbitration
int round_robin_arbration(CentralArbiter *arbiter) {
 // Start from current pointer and search circularly
 for (int offset = 0; offset < arbiter->num_masters; offset++) {
 int idx = (arbiter->rr_pointer + offset) % arbiter->num_masters;
 if (arbiter->masters[idx].breq) {
 arbiter->rr_pointer = (idx + 1) % arbiter->num_masters;
 return idx;
 }
 }
 return -1; // No requesting device
}

// Main arbitration process
void arbitrate(CentralArbiter *arbiter) {
 int winner;

 if (arbiter->arbitration_mode) {
 winner = round_robin_arbration(arbiter);
 } else {
 winner = priority_arbration(arbiter);
 }

 // Grant bus to winner
 if (winner >= 0) {
 arbiter->masters[winner].bgnt = true;
 arbiter->masters[winner].using_bus = true;
 printf("ARBITER: Granting bus to %s (BREQ=%d, Priority=%d)\n",
 arbiter->masters[winner].name,
 arbiter->masters[winner].breq,
 arbiter->masters[winner].priority);
 } else {
 printf("ARBITER: No bus requests pending\n");
 }
}

// Release bus
void release_bus(CentralArbiter *arbiter) {
 for (int i = 0; i < arbiter->num_masters; i++) {
 if (arbiter->masters[i].using_bus) {
 printf("ARBITER: %s releasing bus\n", arbiter->masters[i].name);
 arbiter->masters[i].using_bus = false;
 arbiter->masters[i].breq = false;
 arbiter->masters[i].bgnt = false;
 }
 }
}

// Simulate daisy-chain arbitration
void daisy_chain_arbitation(void) {
 printf("\n--- Daisy-Chain (Priority by Position) ---\n");
 bool bus_grant = true; // Signal starts at arbiter
 bool devices[3] = {false, false, true}; // Only device 2 requests

 printf("Signal starts at arbiter, propagating through chain...\n");

 for (int i = 0; i < 3; i++) {
 printf(" Check Device %d: Grant signal = %d, Request = %d\n", 
 i, bus_grant, devices[i]);

 if (bus_grant && devices[i]) {
 printf(" -> Device %d ACCEPTS bus grant, breaks chain\n", i);
 bus_grant = false; // Chain broken
 break;
 } else if (bus_grant) {
 printf(" -> Passes grant to next device\n");
 }
 }
}

int main() {
 CentralArbiter arbiter;

 printf("====================================\n");
 printf("CENTRALIZED BUS ARBITRATION DEMO\n");
 printf("====================================\n");

 // Test 1: Priority-based
 printf("\n=== Priority-Based Mode ===\n");
 init_arbiter(&arbiter, false);

 // Simulate DMA (priority 2) and Network (priority 1) requesting
 arbiter.masters[1].breq = true; // DMA
 arbiter.masters[2].breq = true; // Network

 printf("Requesting devices: DMA, Network\n");
 arbitrate(&arbiter);
 release_bus(&arbiter);

 // All devices requesting
 for (int i = 0; i < 4; i++) arbiter.masters[i].breq = true;
 printf("\nAll devices requesting...\n");
 arbitrate(&arbiter);
 release_bus(&arbiter);

 // Test 2: Round-robin
 printf("\n=== Round-Robin Mode (Fairness) ===\n");
 init_arbiter(&arbiter, true);

 for (int round = 1; round <= 3; round++) {
 // Simulate alternating requests
 arbiter.masters[round % 4].breq = true;
 printf("\nRound %d: Device %s requests\n", 
 round, arbiter.masters[round % 4].name);
 arbitrate(&arbiter);
 release_bus(&arbiter);
 }

 // Test 3: Daisy-chain
 daisy_chain_arbitation();

 return 0;
}
